mapper.select:
SELECT *
FROM comment
WHERE member_id = #{member_id}
ORDER BY created_date DESC
LIMIT 5;

SELECT * FROM comment
WHERE member_id = #{member_id}
ORDER BY comment_id DESC
LIMIT #{size} OFFSET #{offest}

select count(c.comment_id) from comment c join member m on c.member_id = m.member_id join board b on c.board_id = b.board_id join recipe r on r.recipe_id = c.recipe_id where 1=1
and ( m.nicknam like concat('%',#{keyword},'%') or b.title like concat('%',#{keyword},'%') )
and status = #{status}
